class MathUtils {
  static square(n) {
    return n * n;
  }
}

console.log(MathUtils.square(5));

class MathUtils:
    @staticmethod
    def square(n):
        return n * n
print(MathUtils.square(5))

public class MathUtils {
    public static int square(int n) {
        return n * n;
    }
}
